903→                p.style.display = 'none';
904→                p.classList.remove('active');
905→            });
906→            document.querySelectorAll('.nav-icon-only').forEach(n => n.classList.remove('active'));
907→            const page = document.getElementById('page-' + name);
908→            const nav  = document.getElementById('nav-' + name);
909→            if (page) { page.style.display = 'flex'; page.classList.add('active'); }
910→            if (nav)  nav.classList.add('active');
911→
912→            // Scroll logs to bottom on open
